import{_ as l,c as i,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const c=JSON.parse('{"title":"LangGPT","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/LangGPT-AI工具.md","filePath":"github汇总/AI工具/LangGPT-AI工具.md"}'),t={name:"github汇总/AI工具/LangGPT-AI工具.md"};function n(h,a,o,s,d,g){return e(),i("div",null,a[0]||(a[0]=[r('<h1 id="langgpt" tabindex="-1">LangGPT <a class="header-anchor" href="#langgpt" aria-label="Permalink to “LangGPT”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>LangGPT</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>langgptai</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>AI工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>传统提示词工程依赖零散技巧和反复试错，缺乏系统化的方法论。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>结构化可复用的提示词设计框架，让每个人都能创建高质量的AI提示词。采用类似编程语言的设计思路，提供结构化模板、可复用性、模块化和高效率四大核心特性。通过角色定义（Role）、档案配置（Profile）、技能设定（Skills）、规则约束（Rules）和工作流程（Workflow）五个模块构建完整提示词。支持变量引用、命令定义和条件逻辑等高级功能。提供丰富的示例库和多种AI模型的专门提示词集合。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>超过1.1万GitHub星标</li><li>被数千用户实战验证</li><li>发表学术论文（arXiv:2402.16929）</li><li>提供Claude Code技能插件</li><li>丰富的示例库和视频教程</li><li>支持多种AI模型的专门提示词集合</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><ul><li>11,000+ GitHub stars</li><li>发表学术论文 arXiv:2402.16929</li></ul><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/langgptai/LangGPT" target="_blank" rel="noreferrer">https://github.com/langgptai/LangGPT</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要使用LangGPT框架编写提示词的用户。</p><h3 id="主路径-使用在线工具-推荐" tabindex="-1">主路径：使用在线工具（推荐） <a class="header-anchor" href="#主路径-使用在线工具-推荐" aria-label="Permalink to “主路径：使用在线工具（推荐）”">​</a></h3><p><strong>步骤1：访问LangGPT GPTs</strong></p><ul><li>目标：使用AI自动生成提示词</li><li>位置：浏览器</li><li>操作：访问 LangGPT GPTs（需要GPT-4访问权限）</li><li>成功标志：可以与GPTs对话生成提示词</li><li>失败处理：确认有GPT-4访问权限</li></ul><p><strong>步骤2：描述需求</strong></p><ul><li>目标：让AI生成结构化提示词</li><li>位置：GPTs对话界面</li><li>操作：描述你想要的AI角色和功能</li><li>成功标志：AI生成符合LangGPT格式的提示词</li><li>失败处理：提供更详细的需求描述</li></ul><h3 id="备选路径-手动学习模板" tabindex="-1">备选路径：手动学习模板 <a class="header-anchor" href="#备选路径-手动学习模板" aria-label="Permalink to “备选路径：手动学习模板”">​</a></h3><p><strong>步骤1：访问项目文档</strong></p><ul><li>目标：学习LangGPT模板结构</li><li>位置：浏览器</li><li>操作：访问 <a href="https://github.com/langgptai/LangGPT" target="_blank" rel="noreferrer">https://github.com/langgptai/LangGPT</a> 查看文档</li><li>成功标志：理解模板结构</li><li>失败处理：查看示例库</li></ul><p><strong>步骤2：查看示例</strong></p><ul><li>目标：学习优秀提示词案例</li><li>位置：项目示例库</li><li>操作：浏览Examples目录下的提示词示例</li><li>成功标志：理解如何编写结构化提示词</li><li>失败处理：参考视频教程</li></ul><h3 id="claude-code集成" tabindex="-1">Claude Code集成 <a class="header-anchor" href="#claude-code集成" aria-label="Permalink to “Claude Code集成”">​</a></h3><p><strong>步骤1：下载技能文件</strong></p><ul><li>目标：获取LangGPT技能文件</li><li>位置：项目仓库</li><li>操作：下载 langgpt.skill 文件</li><li>成功标志：文件下载完成</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：安装技能</strong></p><ul><li>目标：将技能安装到Claude Code</li><li>位置：本地</li><li>操作：将文件解压到 ~/.claude/skills/ 目录</li><li>成功标志：技能安装成功</li><li>失败处理：确认目录路径正确</li></ul><p><strong>步骤3：使用技能</strong></p><ul><li>目标：在Claude Code中使用LangGPT</li><li>位置：Claude Code</li><li>操作：输入 /langgpt 命令</li><li>成功标志：技能激活，可以生成提示词</li><li>失败处理：确认技能正确安装</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>GPTs无法访问</strong></p><ul><li>可能原因：没有GPT-4订阅</li><li>解决步骤：升级ChatGPT订阅或使用手动模板</li></ul></li><li><p><strong>Claude Code技能不生效</strong></p><ul><li>可能原因：技能文件路径错误</li><li>解决步骤：确认文件放在正确的 ~/.claude/skills/ 目录</li></ul></li><li><p><strong>生成的提示词效果不好</strong></p><ul><li>可能原因：需求描述不够清晰</li><li>解决步骤：提供更详细的角色定义和功能需求</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://github.com/langgptai/LangGPT" target="_blank" rel="noreferrer">LangGPT文档</a> <a href="/网络环境.html">海外网络环境配置 →</a></li><li><a href="https://arxiv.org/abs/2402.16929" target="_blank" rel="noreferrer">学术论文</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',41)]))}const u=l(t,[["render",n]]);export{c as __pageData,u as default};
